const t={macroDesigner:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Simulez du G-code hors ligne — collez ou écrivez un programme et visualisez la trajectoire de la tête d'impression, la boîte englobante, les totaux de déplacement et d'extrusion, ainsi qu'une estimation de durée, sans toucher à l'imprimante. Parcourez la bibliothèque de macros intégrée à titre de référence."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Aide"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"À propos du Concepteur de macros"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Fermer"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Comment l'utiliser"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Saisissez ou collez du G-code dans l'éditeur (un carré d'exemple est chargé au démarrage)."}},{t:0,b:{t:2,i:[{t:3}],s:"Appuyez sur Simuler — la trajectoire 2D et les statistiques se mettent à jour."}},{t:0,b:{t:2,i:[{t:3}],s:"Les lignes pleines sont des déplacements d'extrusion ; les lignes pointillées et estompées sont des déplacements à vide."}},{t:0,b:{t:2,i:[{t:3}],s:"Parcourez la bibliothèque de macros et insérez-en une pour partir de ses commandes."}}],topics:{simulator:{title:{t:0,b:{t:2,i:[{t:3}],s:"Le simulateur"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Il exécute le programme sur une tête d'impression virtuelle : déplacements G0/G1, G90/G91 (absolu/relatif), M82/M83 (mode extrudeur), G92 (définir la position) et G28 (origine → home). Il indique la trajectoire, la boîte englobante, le déplacement et l'extrusion totaux, une estimation approximative de durée à partir des vitesses d'avance, et une chronologie par commande. Rien n'est envoyé à l'imprimante."}}},motion:{title:{t:0,b:{t:2,i:[{t:3}],s:"Trajectoire et durée"}},body:{t:0,b:{t:2,i:[{t:3}],s:"La vue 2D correspond à la trajectoire XY (le Z figure dans les limites). L'estimation de durée divise la longueur de chaque déplacement par sa vitesse d'avance — elle ignore l'accélération, c'est donc une borne inférieure approximative, pas la durée d'impression exacte. Les commandes que le simulateur ne modélise pas (par ex. les M-codes, les macros de haut niveau) sont listées en avertissements et ignorées."}}},macros:{title:{t:0,b:{t:2,i:[{t:3}],s:"Bibliothèque de macros"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Un ensemble de référence des macros Klipper courantes, avec leur nom, leur rôle et les sections de configuration dont elles ont besoin. « Insérer » dépose les commandes de haut niveau d'une macro dans l'éditeur comme point de départ — notez que celles-ci se développent davantage sur l'imprimante (l'expansion complète Jinja/macro est à venir)."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glossaire"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{gcode:{term:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Le langage de mouvement ligne par ligne que l'imprimante exécute (déplacements, températures, ventilateur, …)."}}},feedrate:{term:{t:0,b:{t:2,i:[{t:3}],s:"Vitesse d'avance (F)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Vitesse de déplacement en mm/min — F1200 équivaut à 20 mm/s. Détermine la rapidité de chaque déplacement."}}},macro:{term:{t:0,b:{t:2,i:[{t:3}],s:"Macro"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Une commande nommée et réutilisable (par ex. QUAD_GANTRY_LEVEL) qui se développe en une séquence de G-code."}}}}},editor:{label:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},simulate:{t:0,b:{t:2,i:[{t:3}],s:"Simuler"}},simulating:{t:0,b:{t:2,i:[{t:3}],s:"Simulation…"}},sample:{t:0,b:{t:2,i:[{t:3}],s:"Charger l'exemple"}},clear:{t:0,b:{t:2,i:[{t:3}],s:"Effacer"}}},library:{label:{t:0,b:{t:2,i:[{t:3}],s:"Macros intégrées"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"Parcourir les macros…"}},insert:{t:0,b:{t:2,i:[{t:3}],s:"Insérer dans l'éditeur"}},requires:{t:0,b:{t:2,i:[{t:3,v:"Nécessite : "},{t:4,k:"sections"}]}},none:{t:0,b:{t:2,i:[{t:3}],s:"—"}}},result:{title:{t:0,b:{t:2,i:[{t:3}],s:"Simulation"}},moves:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" déplacements"}]}},distance:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm de déplacement"}]}},extrude:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm extrudés"}]}},time:{t:0,b:{t:2,i:[{t:3,v:"~"},{t:4,k:"s"},{t:3,v:" s"}]}},bounds:{t:0,b:{t:2,i:[{t:3}],s:"Limites"}},empty:{t:0,b:{t:2,i:[{t:3}],s:"Aucun déplacement à simuler."}}},path:{title:{t:0,b:{t:2,i:[{t:3}],s:"Trajectoire de la tête (XY)"}},noPath:{t:0,b:{t:2,i:[{t:3}],s:"Lancez une simulation pour voir la trajectoire."}}},timeline:{title:{t:0,b:{t:2,i:[{t:3}],s:"Chronologie"}},line:{t:0,b:{t:2,i:[{t:3}],s:"Ligne"}},cmd:{t:0,b:{t:2,i:[{t:3}],s:"Commande"}},action:{t:0,b:{t:2,i:[{t:3}],s:"Action"}}},warnings:{title:{t:0,b:{t:2,i:[{t:3}],s:"Avertissements"}}},explain:{title:{t:0,b:{t:2,i:[{t:3}],s:"Expliquer cette macro"}},travel:{t:0,b:{t:2,i:[{t:3,v:"Déplacement rapide vers X"},{t:4,k:"x"},{t:3,v:" Y"},{t:4,k:"y"},{t:3,v:" à "},{t:4,k:"f"},{t:3,v:" mm/min"}]}},print:{t:0,b:{t:2,i:[{t:3,v:"Mouvement d'impression — extruder "},{t:4,k:"e"},{t:3,v:" mm sur "},{t:4,k:"d"},{t:3,v:" mm jusqu'à X"},{t:4,k:"x"},{t:3,v:" Y"},{t:4,k:"y"},{t:3,v:" à "},{t:4,k:"f"},{t:3,v:" mm/min"}]}},retract:{t:0,b:{t:2,i:[{t:3,v:"Rétracter "},{t:4,k:"e"},{t:3,v:" mm"}]}},prime:{t:0,b:{t:2,i:[{t:3,v:"Extruder "},{t:4,k:"e"},{t:3,v:" mm sur place"}]}},noMove:{t:0,b:{t:2,i:[{t:3}],s:"Aucun mouvement"}},absXYZ:{t:0,b:{t:2,i:[{t:3}],s:"Passer en positionnement absolu (G90)"}},relXYZ:{t:0,b:{t:2,i:[{t:3}],s:"Passer en positionnement relatif (G91)"}},absE:{t:0,b:{t:2,i:[{t:3}],s:"Passer en extrusion absolue (M82)"}},relE:{t:0,b:{t:2,i:[{t:3}],s:"Passer en extrusion relative (M83)"}},setPos:{t:0,b:{t:2,i:[{t:3}],s:"Définir la position actuelle (G92)"}},home:{t:0,b:{t:2,i:[{t:3}],s:"Origine des axes (G28) → origine"}},abs:{t:0,b:{t:2,i:[{t:3}],s:"ABS"}},rel:{t:0,b:{t:2,i:[{t:3}],s:"REL"}},cum:{t:0,b:{t:2,i:[{t:3,v:"jusqu'ici : "},{t:4,k:"d"},{t:3,v:" mm · "},{t:4,k:"e"},{t:3,v:" mm · ~"},{t:4,k:"s"},{t:3,v:" s"}]}},note:{t:0,b:{t:2,i:[{t:3}],s:"Les lignes avec des expressions non résolues ou un contrôle Jinja ne sont pas simulées et sont omises ici."}}},live:{label:{t:0,b:{t:2,i:[{t:3}],s:"Depuis l'imprimante"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"Choisissez une de vos macros installées…"}},hint:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" macros trouvées sur l'imprimante — choisissez-en une pour charger son G-code et la simuler."}]}},unreachable:{t:0,b:{t:2,i:[{t:3}],s:"Imprimante injoignable — connectez-vous pour charger vos macros installées."}},params:{t:0,b:{t:2,i:[{t:3}],s:"Paramètres de la macro"}}},limits:{title:{t:0,b:{t:2,i:[{t:3}],s:"Hors limites / survitesse"}},oob:{t:0,b:{t:2,i:[{t:3,v:"Ligne "},{t:4,k:"line"},{t:3,v:" : "},{t:4,k:"axis"},{t:3,v:"="},{t:4,k:"value"},{t:3,v:" est hors de la zone d'impression ("},{t:4,k:"min"},{t:3,v:"…"},{t:4,k:"max"},{t:3,v:" mm)."}]}},overSpeed:{t:0,b:{t:2,i:[{t:3,v:"Ligne "},{t:4,k:"line"},{t:3,v:" : "},{t:4,k:"value"},{t:3,v:" mm/s dépasse la limite de "},{t:4,k:"limit"},{t:3,v:" mm/s (Klipper la bridera)."}]}},buildArea:{t:0,b:{t:2,i:[{t:3,v:"zone "},{t:4,k:"x"},{t:3,v:"×"},{t:4,k:"y"},{t:3,v:" mm"}]}}}}};export{t as default};
